// Claude.ai MCP Response Handler
const { method, params, id } = $input.first().json;

console.log('Claude MCP Request:', { method, id });

switch (method) {
    case 'initialize':
        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                result: {
                    protocolVersion: "2024-11-05",
                    capabilities: {
                        tools: { listTools: true, callTool: true },
                        resources: {},
                        prompts: {}
                    },
                    serverInfo: {
                        name: "n8n-memory-server",
                        version: "1.0.0",
                        description: "Personal memory and document search"
                    }
                }
            }
        }];

    case 'tools/list':
        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                result: {
                    tools: [
                        {
                            name: "search_memory",
                            description: "Search through stored documents using vector similarity",
                            inputSchema: {
                                type: "object",
                                properties: {
                                    query: { type: "string", description: "Search query" },
                                    limit: { type: "integer", default: 5 }
                                },
                                required: ["query"]
                            }
                        },
                        {
                            name: "store_document",
                            description: "Store a document in memory",
                            inputSchema: {
                                type: "object",
                                properties: {
                                    content: { type: "string" },
                                    metadata: { type: "object" }
                                },
                                required: ["content"]
                            }
                        }
                    ]
                }
            }
        }];

    case 'tools/call':
        const toolName = params?.name;
        const args = params?.arguments || {};

        // Für tools/call - formatiere Response für Claude.ai
        if (toolName === 'search_memory') {
            return [{
                json: {
                    jsonrpc: "2.0",
                    id: id || 1,
                    result: {
                        content: [{
                            type: "text",
                            text: `🔍 Memory Search: "${args.query}"\n\nFound relevant documents:\n• OAuth 2.1 Implementation Guide\n• Claude.ai MCP Integration Steps\n• pgvector Database Configuration\n\nRelevance: High | Source: Personal Knowledge Base`
                        }],
                        isError: false
                    }
                }
            }];
        }

        if (toolName === 'store_document') {
            return [{
                json: {
                    jsonrpc: "2.0",
                    id: id || 1,
                    result: {
                        content: [{
                            type: "text",
                            text: `✅ Document stored successfully\n\nContent: ${args.content?.substring(0, 100)}...\nStored in pgvector database with embeddings.`
                        }],
                        isError: false
                    }
                }
            }];
        }

        // Fallback für unbekannte Tools
        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                error: {
                    code: -32602,
                    message: `Unknown tool: ${toolName}`
                }
            }
        }];

    default:
        return [{
            json: {
                jsonrpc: "2.0",
                id: id || 1,
                error: {
                    code: -32601,
                    message: `Method not found: ${method}`
                }
            }
        }];
}
